  const [direction,setDirection]   = useState(1);
  const [comments,setComments]     = useState([{name:"Bagas",status:"Hadir",msg:"Semoga lancar dan barokah 🙏",time:"1 Jul 2026"}]);
  const [copied,setCopied]         = useState("");
  const transitioning              = useRef(false);

const touchStartX = useRef(0);
const touchStartY = useRef(0);

  const touchStart = useRef({x:0,y:0});

  useEffect(() => {
    const audio = new Audio("/music/eight.mp3");
    audio.loop = true;

    const startMusic = () => {
      audio.play().catch(() => {});
      document.removeEventListener("click", startMusic);
    };

    document.addEventListener("click", startMusic);

    return () => {
      audio.pause();
      document.removeEventListener("click", startMusic);
    };
  }, []);


  const handleOpen=()=>{setCoverPhase("blooming");setTimeout(()=>setOpened(true),800);};
  const tabOrder=TABS.map(t=>t.id);
  const changeTab=(newTab)=>{
    if(newTab===tab||transitioning.current)return;
    transitioning.current=true;
    const dir=tabOrder.indexOf(newTab)>tabOrder.indexOf(tab)?1:-1;
    setDirection(dir);setPhase("exit");
    setTimeout(()=>{
      setDisplayTab(newTab);setTab(newTab);setPhase("enter");
      requestAnimationFrame(()=>requestAnimationFrame(()=>{
        setPhase("idle");setTimeout(()=>{transitioning.current=false;},450);
      }));
    },280);
  };


  const handleTouchStart = (e) => {
    touchStartX.current = e.touches[0].clientX;
    touchStartY.current = e.touches[0].clientY;
  };

  const handleTouchEnd = (e) => {
    const endX = e.changedTouches[0].clientX;
    const endY = e.changedTouches[0].clientY;
    const diffX = touchStartX.current - endX;
    const diffY = touchStartY.current - endY;

    // Kalau gerakannya lebih ke atas/bawah, biarkan scroll normal
    if (Math.abs(diffX) < Math.abs(diffY)) return;
    if (Math.abs(diffX) < 60) return;

    const currentIndex = tabOrder.indexOf(tab);

    if (diffX > 0 && currentIndex < tabOrder.length - 1) {
      changeTab(tabOrder[currentIndex + 1]);
    }

    if (diffX < 0 && currentIndex > 0) {
      changeTab(tabOrder[currentIndex - 1]);
    }
  };


  
  const goNext=()=>{
    const i=tabOrder.indexOf(tab);
    if(i<tabOrder.length-1) changeTab(tabOrder[i+1]);
  };

  const goPrev=()=>{
    const i=tabOrder.indexOf(tab);
    if(i>0) changeTab(tabOrder[i-1]);
  };

  const onTouchStart=(e)=>{
    touchStart.current={
      x:e.touches[0].clientX,
      y:e.touches[0].clientY
    };
  };

  const onTouchEnd=(e)=>{
    const dx=e.changedTouches[0].clientX-touchStart.current.x;
    const dy=e.changedTouches[0].clientY-touchStart.current.y;

    if(Math.abs(dx)>Math.abs(dy)){
      if(dx<-50) goNext();
      if(dx>50) goPrev();
    }else{
      if(dy<-50) goNext();
      if(dy>50) goPrev();
    }
  };

const idx=tabOrder.indexOf(tab);
  const vs=Math.max(0,Math.min(idx-2,TABS.length-5));
  const vtabs=TABS.slice(vs,vs+5);

  const nextTab=()=>{
    const i=tabOrder.indexOf(tab);
    if(i<TABS.length-1){
      changeTab(tabOrder[i+1]);
    }
  };

  const prevTab=()=>{
    const i=tabOrder.indexOf(tab);
    if(i>0){
      changeTab(tabOrder[i-1]);
    }
  };
  const divider=<div style={{width:44,height:1,background:GOLD_LIGHT,margin:"13px auto"}}/>;
